import React, { useState } from "react";
import axios from "axios";

const CreateEvent = () => {
  const [loading, setLoading] = useState(false);

  const [eventData, setEventData] = useState({
    name: "",
    description: "",
    type: "normal",
    eligibility: "",
    registrationDeadline: "",
    startDate: "",
    endDate: "",
    registrationLimit: "",
    registrationFee: "",
    tags: "",
    status: "draft",
  });

  const [customFields, setCustomFields] = useState([]);
  const [merchandiseConfig, setMerchandiseConfig] = useState({
    items: [],
    purchaseLimit: 1,
  });

  const handleChange = (e) => {
    setEventData({ ...eventData, [e.target.name]: e.target.value });
  };

  /* ==============================
     FORM BUILDER LOGIC
  ============================== */

  const addField = (type) => {
    const newField = {
      id: Date.now(),
      label: "",
      type,
      required: false,
      options: type === "dropdown" ? ["Option 1"] : [],
    };

    setCustomFields([...customFields, newField]);
  };

  const updateField = (id, key, value) => {
    setCustomFields((fields) =>
      fields.map((field) =>
        field.id === id ? { ...field, [key]: value } : field
      )
    );
  };

  const deleteField = (id) => {
    setCustomFields(customFields.filter((field) => field.id !== id));
  };

  const moveField = (index, direction) => {
    const newFields = [...customFields];
    const targetIndex = direction === "up" ? index - 1 : index + 1;

    if (targetIndex < 0 || targetIndex >= newFields.length) return;

    [newFields[index], newFields[targetIndex]] = [
      newFields[targetIndex],
      newFields[index],
    ];

    setCustomFields(newFields);
  };

  /* ==============================
     MERCHANDISE LOGIC
  ============================== */

  const addItem = () => {
    setMerchandiseConfig({
      ...merchandiseConfig,
      items: [
        ...merchandiseConfig.items,
        { name: "", sizes: "", colors: "", stock: 0 },
      ],
    });
  };

  const updateItem = (index, key, value) => {
    const updatedItems = [...merchandiseConfig.items];
    updatedItems[index][key] = value;
    setMerchandiseConfig({ ...merchandiseConfig, items: updatedItems });
  };

  /* ==============================
     SAVE EVENT
  ============================== */

  const handleSubmit = async (statusType) => {
    try {
      setLoading(true);

      const payload = {
        ...eventData,
        status: statusType,
        tags: eventData.tags.split(",").map((t) => t.trim()),
        customFields: eventData.type === "normal" ? customFields : [],
        merchandiseConfig:
          eventData.type === "merchandise" ? merchandiseConfig : null,
      };

      await axios.post("http://localhost:5000/api/events", payload, {
        headers: {
          Authorization: `Bearer ${localStorage.getItem("token")}`,
        },
      });

      alert(`Event ${statusType === "draft" ? "saved" : "published"}!`);
    } catch (err) {
      console.error(err);
      alert("Failed to create event");
    } finally {
      setLoading(false);
    }
  };

  /* ==============================
     UI
  ============================== */

  return (
    <div style={styles.container}>
      <h2>Create Event</h2>

      {/* ================= EVENT DETAILS ================= */}
      <div style={styles.card}>
        <h3>Event Details</h3>

        <input
          name="name"
          placeholder="Event Name"
          value={eventData.name}
          onChange={handleChange}
        />

        <textarea
          name="description"
          placeholder="Description"
          value={eventData.description}
          onChange={handleChange}
        />

        <select name="type" value={eventData.type} onChange={handleChange}>
          <option value="normal">Normal Event</option>
          <option value="merchandise">Merchandise Event</option>
        </select>

        <input
          name="eligibility"
          placeholder="Eligibility"
          value={eventData.eligibility}
          onChange={handleChange}
        />

        <input
          type="datetime-local"
          name="registrationDeadline"
          onChange={handleChange}
        />

        <input type="datetime-local" name="startDate" onChange={handleChange} />
        <input type="datetime-local" name="endDate" onChange={handleChange} />

        <input
          type="number"
          name="registrationLimit"
          placeholder="Registration Limit"
          onChange={handleChange}
        />

        <input
          type="number"
          name="registrationFee"
          placeholder="Registration Fee"
          onChange={handleChange}
        />

        <input
          name="tags"
          placeholder="Tags (comma separated)"
          value={eventData.tags}
          onChange={handleChange}
        />
      </div>

      {/* ================= NORMAL EVENT FORM BUILDER ================= */}
      {eventData.type === "normal" && (
        <div style={styles.card}>
          <h3>Custom Registration Form Builder</h3>

          <div style={styles.buttonRow}>
            <button onClick={() => addField("text")}>+ Text</button>
            <button onClick={() => addField("dropdown")}>
              + Dropdown
            </button>
            <button onClick={() => addField("checkbox")}>
              + Checkbox
            </button>
            <button onClick={() => addField("file")}>+ File</button>
          </div>

          {customFields.map((field, index) => (
            <div key={field.id} style={styles.fieldBox}>
              <input
                placeholder="Field Label"
                value={field.label}
                onChange={(e) =>
                  updateField(field.id, "label", e.target.value)
                }
              />

              {field.type === "dropdown" && (
                <input
                  placeholder="Comma separated options"
                  value={field.options.join(",")}
                  onChange={(e) =>
                    updateField(
                      field.id,
                      "options",
                      e.target.value.split(",")
                    )
                  }
                />
              )}

              <label>
                Required
                <input
                  type="checkbox"
                  checked={field.required}
                  onChange={(e) =>
                    updateField(field.id, "required", e.target.checked)
                  }
                />
              </label>

              <div>
                <button onClick={() => moveField(index, "up")}>↑</button>
                <button onClick={() => moveField(index, "down")}>↓</button>
                <button onClick={() => deleteField(field.id)}>Delete</button>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* ================= MERCHANDISE EVENT ================= */}
      {eventData.type === "merchandise" && (
        <div style={styles.card}>
          <h3>Merchandise Configuration</h3>

          <button onClick={addItem}>+ Add Item</button>

          {merchandiseConfig.items.map((item, index) => (
            <div key={index} style={styles.fieldBox}>
              <input
                placeholder="Item Name"
                onChange={(e) =>
                  updateItem(index, "name", e.target.value)
                }
              />

              <input
                placeholder="Sizes (S,M,L)"
                onChange={(e) =>
                  updateItem(index, "sizes", e.target.value)
                }
              />

              <input
                placeholder="Colors (Black,White)"
                onChange={(e) =>
                  updateItem(index, "colors", e.target.value)
                }
              />

              <input
                type="number"
                placeholder="Stock"
                onChange={(e) =>
                  updateItem(index, "stock", e.target.value)
                }
              />
            </div>
          ))}

          <input
            type="number"
            placeholder="Purchase Limit Per Participant"
            value={merchandiseConfig.purchaseLimit}
            onChange={(e) =>
              setMerchandiseConfig({
                ...merchandiseConfig,
                purchaseLimit: e.target.value,
              })
            }
          />
        </div>
      )}

      {/* ================= ACTION BUTTONS ================= */}
      <div style={styles.buttonRow}>
        <button onClick={() => handleSubmit("draft")} disabled={loading}>
          Save Draft
        </button>

        <button onClick={() => handleSubmit("published")} disabled={loading}>
          Publish Event
        </button>
      </div>
    </div>
  );
};

